128	// Helper to format a code point as a readable string
129	static std::string format_codepoint(uint32_t cp) {
130	    if (cp >= 32 && cp < 127) {
131	        return std::string("'") + static_cast<char>(cp) + "'";
132	    } else if (cp == '\n') {
133	        return "'\\n'";
134	    } else if (cp == '\r') {
135	        return "'\\r'";
136	    } else if (cp == '\t') {
137	        return "'\\t'";
138	    } else {
139	        return "U+" + std::to_string(cp);
140	    }
141	}
