143	// Helper to format expected element from grammar stack
144	static std::string format_expected_element(const llama_grammar_rules & /* rules*/, const llama_grammar_element * elem) {
145	    if (!elem) {
146	        return "<end>";
147	    }
148	
149	    switch (elem->type) {
150	        case LLAMA_GRETYPE_END:
151	            return "<end of rule>";
152	        case LLAMA_GRETYPE_ALT:
153	            return "<alternative>";
154	        case LLAMA_GRETYPE_RULE_REF:
155	            {
156	                // Find rule name - just show rule ID for now
157	                return "<rule-" + std::to_string(elem->value) + ">";
158	            }
159	        case LLAMA_GRETYPE_CHAR:
160	            {
161	                std::string                   result;
162	                const llama_grammar_element * pos   = elem;
163	                bool                          first = true;
164	
165	                do {
166	                    if (!first) {
167	                        result += " | ";
168	                    }
169	                    first = false;
170	
171	                    if (pos[1].type == LLAMA_GRETYPE_CHAR_RNG_UPPER) {
172	                        // Range like [a-z]
173	                        result += "[" + format_codepoint(pos->value) + "-" + format_codepoint(pos[1].value) + "]";
174	                        pos += 2;
175	                    } else {
176	                        result += format_codepoint(pos->value);
177	                        pos += 1;
178	                    }
