static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    data.prompt           = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format           = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens = {
        "[TOOL_CALLS]",
    };

    auto has_tools       = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
            // Nemo/Mistral tool call format:
            //   [TOOL_CALLS][{"name": "func", "arguments": {...}, "id": "123456789"}]
            // section_start includes the opening '[' of the JSON array, so array_wrapped = false.
            auto tool_calls = p.standard_json_tools(
                /* section_start     = */ "[TOOL_CALLS][",
                /* section_end       = */ "]",
                /* tools             = */ inputs.tools,
                /* parallel_tool_calls = */ inputs.parallel_tool_calls,
                /* force_tool_calls  = */ inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED,
                /* name_key          = */ "name",
                /* args_key          = */ "arguments",
                /* array_wrapped     = */ false,
                /* function_is_key   = */ false,
                /* call_id_key       = */ "id",
                /* gen_call_id_key   = */ "",
                /* parameters_order  = */ {"name", "arguments", "id"});

            // Content is everything before the optional [TOOL_CALLS] section.
            return p.literal(inputs.generation_prompt) +
                   (inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED
                        ? p.eps()
                        : p.optional(p.content(p.until("[TOOL_CALLS]")))) +
                   tool_calls + p.end();
        }

        // Content-only (v0.3 base template, no tool calls defined).
        include_grammar = false;
        return p.literal(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;

        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto         schema   = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    return data;
}
```

**Rationale:**
- The function signature, `data.format = COMMON_CHAT_FORMAT_PEG_NATIVE`, and overall structure follow every other specialized handler exactly.
- The tool call branch uses `standard_json_tools` with the parameters verified from the existing Nemo test cases: `section_start = "[TOOL_CALLS]["` (includes the `[` that opens the JSON array), `section_end = "]"`, `name_key = "name"`, `args_key = "arguments"`, `call_id_key = "id"`, `parameters_order = {"name", "arguments", "id"}`.
- `array_wrapped = false` because the `[` and `]` array delimiters are embedded in `section_start`/`section_end` rather than being added by the function.
- `standard_json_tools` internally wraps the tool section with `trigger_rule("tool-call", ...)`, so there is no need to call `trigger_rule` explicitly in the parser lambda.
- The content parser uses `p.until("[TOOL_CALLS]")` as the stop marker when tools are active, matching the pattern from the Ministral-3 handler.
- When `tool_choice == REQUIRED`, the content section is replaced by `p.eps()` (empty match) so the parser goes straight to the tool call — also matching the Ministral-3 pattern.
- The grammar trigger uses `COMMON_GRAMMAR_TRIGGER_TYPE_WORD` with `"[TOOL_CALLS]"`, which is the standard word-boundary trigger used throughout other Mistral-family handlers.
- `supports_thinking = false` is explicit — this template family has no reasoning block.
- `preserved_tokens` keeps `"[TOOL_CALLS]"` to prevent tokenizers from splitting this structural marker.
