284	common_peg_parser analyze_tools::build_tool_parser_json_native(parser_build_context & ctx) const {
285	    auto &       p           = ctx.p;
286	    const auto & inputs      = ctx.inputs;
287	    bool         force_tools = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED;
288	
289	    // Build effective field names with dot notation if function_field is set
290	    std::string name_field = format.name_field;
291	    std::string args_field = format.args_field;
292	
293	    if (!format.function_field.empty() && format.function_field != "function" &&
294	        name_field.find('.') == std::string::npos) {
295	        name_field = format.function_field + "." + name_field;
296	        args_field = format.function_field + "." + args_field;
297	    }
298	
299	    auto tools_parser = p.standard_json_tools(
300	        format.section_start, format.section_end, inputs.tools, inputs.parallel_tool_calls,
301	        inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED, name_field, args_field, format.tools_array_wrapped,
302	        format.fun_name_is_key, format.id_field, format.gen_id_field, format.parameter_order);
303	
304	    // Handle content wrappers if present
305	    if (ctx.content && ctx.content->is_always_wrapped()) {
306	        auto wrapped_content = ctx.content->build_optional_wrapped(ctx);
307	        return ctx.reasoning_parser + wrapped_content + tools_parser + p.end();
308	    }
309	
310	    std::string tool_start = "{";
311	    if (!format.section_start.empty()) {
312	        tool_start = format.section_start;
313	    } else if (!format.per_call_start.empty()) {
314	        tool_start = format.per_call_start;
315	    }
316	
317	    return ctx.reasoning_parser + (force_tools ? p.eps() : p.optional(p.content(p.until(tool_start)))) + tools_parser +
318	           p.end();
